typedef enum SDL_AsyncIOTaskType
{
 SDL_ASYNCIO_TASK_READ, /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ قراءة من المصدر المرتبط، لذلك يعاملها النظام كعملية إدخال بيانات. */
 SDL_ASYNCIO_TASK_WRITE, /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ كتابة إلى الوجهة المرتبطة، لذلك يعاملها النظام كعملية إخراج بيانات. */
 SDL_ASYNCIO_TASK_CLOSE /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ إغلاقًا للمورد أو المجرى المرتبط بعد اكتمال العمل عليه. */
} SDL_AsyncIOTaskType;
